function binaryTreeMaximumPathSum(data) {
    const nodes = data.split(' ').map(x => x === 'null' ? null : parseInt(x));
    class TreeNode {
        constructor(value) {
            this.value = value;
            this.left = null;
            this.right = null;
        }
    }
    function buildTree(index) {
        if (index >= nodes.length || nodes[index] === null) return null;
        const node = new TreeNode(nodes[index]);
        node.left = buildTree(2 * index + 1);
        node.right = buildTree(2 * index + 2);
        return node;
    }
    function findMaxPathSum(node) {
        if (!node) return 0;
        const leftSum = Math.max(findMaxPathSum(node.left), 0);
        const rightSum = Math.max(findMaxPathSum(node.right), 0);
        const currentMax = node.value + leftSum + rightSum;
        maxSum = Math.max(maxSum, currentMax);
        return node.value + Math.max(leftSum, rightSum);
    }
    let maxSum = -Infinity;
    const root = buildTree(0);
    findMaxPathSum(root);
    return maxSum;
}

