        if (!root) return 0;
        int maxSum = INT_MIN;
        vector<int> path;
        findPaths(root, path, maxSum);
        return maxSum;
    }
    private:
    void findPaths(TreeNode* node, vector<int>& path, int& maxSum) {
        if (!node) return;
        path.push_back(node->val);
        int currentSum = 0;
        for (int i = path.size() - 1; i >= 0; --i) {
            currentSum += path[i];
            maxSum = max(maxSum, currentSum);
        }
        findPaths(node->left, path, maxSum);
        findPaths(node->right, path, maxSum);
        path.pop_back();
    }
