public class TreeNode {
    public int val;
    public TreeNode left;
    public TreeNode right;
    public TreeNode(int x) { val = x; }
}

public class Solution {
    public int binaryTreeMaximumPathSum(TreeNode data) {
        if (data == null) return 0;
        int maxSum = int.MinValue;
        List<int> pathSums = new List<int>();
        GeneratePaths(data, pathSums);
        foreach (int sum in pathSums) {
            if (sum > maxSum) {
                maxSum = sum;
            }
        }
        return maxSum;
    }

    private void GeneratePaths(TreeNode node, List<int> pathSums) {
        if (node == null) return;
        List<int> currentPath = new List<int>();
        FindPaths(node, currentPath, pathSums);
        GeneratePaths(node.left, pathSums);
        GeneratePaths(node.right, pathSums);
    }

    private void FindPaths(TreeNode node, List<int> currentPath, List<int> pathSums) {
        if (node == null) return;
        currentPath.Add(node.val);
        int currentSum = 0;
        for (int i = currentPath.Count - 1; i >= 0; i--) {
            currentSum += currentPath[i];
            pathSums.Add(currentSum);
        }
        FindPaths(node.left, currentPath, pathSums);
        FindPaths(node.right, currentPath, pathSums);
        currentPath.RemoveAt(currentPath.Count - 1);
    }
}

